import { toolDefinition } from "@tanstack/ai"
import { z } from "zod"
import { db } from "#/db"
import { destinations } from "#/db/schema"
import { eq } from "drizzle-orm"

const destinationInfoSchema = z.object({
	country: z.string(),
	region: z.string(),
	climate: z.string(),
	bestTime: z.string(),
	attractions: z.array(z.string()),
	cuisine: z.string(),
	budget: z.string(),
	timezone: z.string(),
	language: z.string(),
})

export const getDestinationInfoToolDef = toolDefinition({
	name: "getDestinationInfo",
	description:
		"Look up information about a travel destination including attractions, climate, budget, cuisine and best time to visit.",
	inputSchema: z.object({
		destination: z.string().describe("Name of the city or destination to look up"),
	}),
	outputSchema: z.union([
		destinationInfoSchema,
		z.object({ error: z.string() }),
	]),
})

export const getDestinationInfo = getDestinationInfoToolDef.server(
	async ({ destination }) => {
		const rows = await db
			.select()
			.from(destinations)
			.where(eq(destinations.name, destination))
			.limit(1)

		if (rows.length === 0) {
			return {
				error: `No information found for "${destination}". Try one of the featured destinations.`,
			}
		}

		return rows[0].info as z.infer<typeof destinationInfoSchema>
	},
)

import {
	createChatClientOptions,
	fetchServerSentEvents,
	useChat,
} from "@tanstack/ai-react"
import type { InferChatMessages } from "@tanstack/ai-react"

const chatOptions = createChatClientOptions({
	connection: fetchServerSentEvents("/api/ai/travel-chat"),
})

export type TravelChatMessages = InferChatMessages<typeof chatOptions>

export const useTravelChat = () => useChat(chatOptions)

import { createAPIFileRoute } from "@tanstack/react-start/api"
import { chat, toServerSentEventsResponse } from "@tanstack/ai"
import { geminiText } from "@tanstack/ai-gemini"
import { getDestinationInfo } from "#/lib/tools/travel-tools"

const SYSTEM_PROMPT = `You are a friendly travel assistant helping users discover destinations and build their travel profile.

You have access to a getDestinationInfo tool to look up real information about destinations.
Always use the tool when a user asks about a specific destination — never make up details.

When chatting:
- Ask about travel preferences (climate, budget, activities, cuisine)
- Use destination info to make personalised suggestions
- Be concise and conversational
- If a destination isn't in the database, say so honestly`

export const APIRoute = createAPIFileRoute("/api/ai/travel-chat")({
	POST: async ({ request }) => {
		const { messages } = await request.json()

		const stream = chat({
			adapter: geminiText({
				apiKey: process.env.GOOGLE_GENERATIVE_AI_API_KEY!,
			}),
			model: "gemini-2.0-flash",
			system: SYSTEM_PROMPT,
			messages,
			tools: [getDestinationInfo],
			maxIterations: 5,
		})

		return toServerSentEventsResponse(stream)
	},
})

import { useEffect, useRef, useState } from "react"
import { Send, BotIcon } from "lucide-react"
import { Streamdown } from "streamdown"
import { useTravelChat } from "#/lib/ai/travel-chat-hook"
import type { TravelChatMessages } from "#/lib/ai/travel-chat-hook"

function Messages({ messages }: { messages: TravelChatMessages }) {
	const bottomRef = useRef<HTMLDivElement>(null)

	useEffect(() => {
		bottomRef.current?.scrollIntoView({ behavior: "smooth" })
	}, [messages])

	if (!messages.length) {
		return (
			<div className="flex flex-1 flex-col items-center justify-center gap-3 text-[var(--sea-ink-soft)]">
				<BotIcon size={36} className="opacity-40" />
				<p className="text-sm">
					Ask me about destinations, travel tips, or tell me where you want to go!
				</p>
			</div>
		)
	}

	return (
		<div className="flex flex-1 flex-col gap-1 overflow-y-auto py-4">
			{messages.map(({ id, role, parts }) => (
				<div
					key={id}
					className={`flex gap-3 px-4 py-2 ${role === "assistant" ? "bg-[var(--chip-bg)]" : ""}`}
				>
					<div
						className={`mt-0.5 flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-md text-xs font-bold text-white ${
							role === "assistant"
								? "bg-[var(--lagoon-deep)]"
								: "bg-[var(--sea-ink-soft)]"
						}`}
					>
						{role === "assistant" ? "AI" : "Y"}
					</div>
					<div className="min-w-0 flex-1 text-sm text-[var(--sea-ink)]">
						{parts.map((part, i) => {
							if (part.type === "text" && part.content) {
								return <Streamdown key={i}>{part.content}</Streamdown>
							}
							return null
						})}
					</div>
				</div>
			))}
			<div ref={bottomRef} />
		</div>
	)
}

export default function TravelChat() {
	const { messages, sendMessage } = useTravelChat()
	const [input, setInput] = useState("")

	const submit = () => {
		const text = input.trim()
		if (!text) return
		sendMessage(text)
		setInput("")
	}

	return (
		<div className="island-shell flex h-[600px] flex-col overflow-hidden rounded-2xl">
			{/* Header */}
			<div className="flex items-center gap-2 border-b border-[var(--line)] px-5 py-4">
				<BotIcon size={20} className="text-[var(--lagoon-deep)]" />
				<h2 className="text-base font-semibold text-[var(--sea-ink)]">
					Travel Assistant
				</h2>
			</div>

			{/* Messages */}
			<Messages messages={messages} />

			{/* Input */}
			<div className="border-t border-[var(--line)] px-4 py-3">
				<form
					onSubmit={(e) => {
						e.preventDefault()
						submit()
					}}
					className="relative"
				>
					<textarea
						value={input}
						onChange={(e) => setInput(e.target.value)}
						onKeyDown={(e) => {
							if (e.key === "Enter" && !e.shiftKey) {
								e.preventDefault()
								submit()
							}
						}}
						placeholder="Where do you want to go?"
						className="demo-textarea w-full resize-none pr-12 text-sm"
						rows={1}
						style={{ minHeight: "40px", maxHeight: "120px" }}
						onInput={(e) => {
							const el = e.target as HTMLTextAreaElement
							el.style.height = "auto"
							el.style.height = `${Math.min(el.scrollHeight, 120)}px`
						}}
					/>
					<button
						type="submit"
						disabled={!input.trim()}
						className="absolute right-3 top-1/2 -translate-y-1/2 rounded-lg p-1.5 text-[var(--lagoon-deep)] transition hover:bg-[var(--chip-bg)] disabled:opacity-30"
					>
						<Send size={16} />
					</button>
				</form>
			</div>
		</div>
	)
}

