import { chat, maxIterations, toServerSentEventsResponse } from "@tanstack/ai"
import { geminiText } from "@tanstack/ai-gemini"
import { createFileRoute } from "@tanstack/react-router"
import { getDestinationInfo } from "#/lib/tools/travel-tools"
import { db } from "#/db"
import { conversations } from "#/db/schema"
import { asc, desc } from "drizzle-orm"

const SYSTEM_PROMPT = `You are a friendly travel assistant helping users discover destinations and build their travel profile.

You have access to a getDestinationInfo tool to look up real information about destinations.
Always use the tool when a user asks about a specific destination — never make up details.

When chatting:
- Ask about travel preferences (climate, budget, activities, cuisine)
- Use destination info to make personalised suggestions
- Be concise and conversational
- If a destination isn't in the database, say so honestly`

async function saveConversation(message: { role: string; content: string }) {
	await db.insert(conversations).values({
		role: message.role,
		content: message.content,
	})
}

async function handler({ request }: { request: Request }) {
	if (!process.env.GOOGLE_GENERATIVE_AI_API_KEY) {
		return new Response("Missing GOOGLE_GENERATIVE_AI_API_KEY", { status: 500 })
	}

	let messages: Array<{ role: string; content: string }>
	try {
		const body = await request.json()
		messages = body.messages ?? []
	} catch {
		return new Response("Invalid JSON body", { status: 400 })
	}

	// Save user messages to DB
	for (const msg of messages) {
		if (msg.role === "user") {
			await saveConversation(msg)
		}
	}

	const stream = chat({
		adapter: geminiText("gemini-2.5-flash", {
			apiKey: process.env.GOOGLE_GENERATIVE_AI_API_KEY,
		}),
		systemPrompts: [SYSTEM_PROMPT],
		messages: messages as any,
		tools: [getDestinationInfo],
		agentLoopStrategy: maxIterations(8),
	})

	const response = toServerSentEventsResponse(stream)
	return new Response(response, {
		headers: {
			"Content-Type": "text/event-stream",
			"Cache-Control": "no-cache",
			Connection: "keep-alive",
		},
	})
}

export const Route = createFileRoute("/api/ai/travel-chat")({
	server: {
		handlers: {
			POST: handler,
		},
	},
})

import { z } from "zod"
import { createTRPCRouter, publicProcedure } from "./init"
import { db } from "#/db"
import { conversations, travelProfile, conflicts, destinations } from "#/db/schema"
import { desc, asc, eq } from "drizzle-orm"

export const trpcRouter = createTRPCRouter({
	// Destinations
	destinations: createTRPCRouter({
		list: publicProcedure.query(async () => {
			return db.select().from(destinations).orderBy(asc(destinations.name))
		}),
		getByName: publicProcedure
			.input(z.object({ name: z.string() }))
			.query(async ({ input }) => {
				const result = await db
					.select()
					.from(destinations)
					.where(eq(destinations.name, input.name))
					.limit(1)
				return result[0] ?? null
			}),
	}),

	// Conversations
	conversations: createTRPCRouter({
		list: publicProcedure.query(async () => {
			return db
				.select()
				.from(conversations)
				.orderBy(desc(conversations.createdAt))
				.limit(100)
		}),
		create: publicProcedure
			.input(z.object({ role: z.enum(["user", "assistant"]), content: z.string() }))
			.mutation(async ({ input }) => {
				const result = await db.insert(conversations).values(input).returning()
				return result[0]
			}),
		clear: publicProcedure.mutation(async () => {
			await db.delete(conversations)
			return { success: true }
		}),
	}),

	// Travel Profile
	profile: createTRPCRouter({
		get: publicProcedure.query(async () => {
			const result = await db.select().from(travelProfile).limit(1)
			return result[0] ?? null
		}),
		update: publicProcedure
			.input(
				z.object({
					interests: z.array(z.string()).optional(),
					budget: z.enum(["budget", "moderate", "luxury"]).optional(),
					climate: z.array(z.string()).optional(),
					activities: z.array(z.string()).optional(),
					dreamDestinations: z.array(z.string()).optional(),
					avoidedDestinations: z.array(z.string()).optional(),
				}),
			)
			.mutation(async ({ input }) => {
				const existing = await db.select().from(travelProfile).limit(1)
				const preferences = {
					...(existing[0]?.preferences as Record<string, unknown> ?? {}),
					...input,
					updatedAt: new Date().toISOString(),
				}

				if (existing[0]) {
					await db
						.update(travelProfile)
						.set({ preferences: preferences as any, updatedAt: new Date() })
						.where(eq(travelProfile.id, existing[0].id))
					return { ...existing[0], preferences }
				} else {
					const result = await db
						.insert(travelProfile)
						.values({ preferences: preferences as any })
						.returning()
					return result[0]
				}
			}),
	}),

	// Conflicts
	conflicts: createTRPCRouter({
		list: publicProcedure.query(async () => {
			return db
				.select()
				.from(conflicts)
				.orderBy(desc(conflicts.createdAt))
				.limit(50)
		}),
		resolve: publicProcedure
			.input(z.object({ id: z.number(), resolution: z.string() }))
			.mutation(async ({ input }) => {
				await db
					.update(conflicts)
					.set({ resolved: true })
					.where(eq(conflicts.id, input.id))
				return { success: true }
			}),
	}),
})

export type TRPCRouter = typeof trpcRouter

import { toolDefinition } from "@tanstack/ai"
import { z } from "zod"
import { db } from "#/db"
import { travelProfile, conflicts, conversations } from "#/db/schema"
import { desc } from "drizzle-orm"

const ProfileInputSchema = z.object({
	interests: z.array(z.string()).optional(),
	budget: z.enum(["budget", "moderate", "luxury"]).optional(),
	climate: z.array(z.string()).optional(),
	activities: z.array(z.string()).optional(),
	dreamDestinations: z.array(z.string()).optional(),
	avoidedDestinations: z.array(z.string()).optional(),
})

export const extractProfileToolDef = toolDefinition({
	name: "extractProfile",
	description:
		"Extract or update the traveler's profile preferences from the conversation. Use this tool after gathering new information about their travel preferences. Always call this tool when the user reveals new information about their travel style, budget, interests, or destinations they want to visit or avoid.",
	inputSchema: ProfileInputSchema,
	outputSchema: z.object({
		updated: z.boolean(),
		conflicts: z.array(
			z.object({
				field: z.string(),
				previous: z.string(),
				new: z.string(),
			}),
		),
	}),
})

async function detectConflict(
	field: string,
	newValue: unknown,
	existing: Record<string, unknown>,
): Promise<{ hasConflict: boolean; previous: string; new: string } | null> {
	const existingValue = existing[field]
	if (!existingValue) return null
	if (JSON.stringify(existingValue) === JSON.stringify(newValue)) return null

	// Special handling for arrays
	if (Array.isArray(existingValue) && Array.isArray(newValue)) {
		const existingSet = new Set(existingValue)
		const newSet = new Set(newValue)
		const removed = existingValue.filter((v) => !newSet.has(v))
		const added = newValue.filter((v) => !existingSet.has(v))

		if (removed.length === 0 && added.length === 0) return null

		return {
			hasConflict: true,
			previous: `${existingValue.length} items: ${existingValue.join(", ")}`,
			new: `${newValue.length} items: ${newValue.join(", ")}`,
		}
	}

	return {
		hasConflict: true,
		previous: String(existingValue),
		new: String(newValue),
	}
}

async function saveConflict(
	field: string,
	previousValue: unknown,
	newValue: unknown,
	conversationId: number,
) {
	await db.insert(conflicts).values({
		field,
		previousValue: previousValue as any,
		newValue: newValue as any,
		conversationId,
		resolved: false,
	})
}

export const extractProfile = extractProfileToolDef.server(async ({ input }) => {
	const existingResult = await db
		.select()
		.from(travelProfile)
		.orderBy(desc(travelProfile.updatedAt))
		.limit(1)

	const existing = (existingResult[0]?.preferences as Record<string, unknown>) ?? {}
	const conversationResult = await db
		.select()
		.from(conversations)
		.orderBy(desc(conversations.id))
		.limit(1)
	const conversationId = conversationResult[0]?.id ?? 0

	const conflictResults: Array<{ field: string; previous: string; new: string }> = []

	// Check each field for conflicts
	for (const [key, value] of Object.entries(input)) {
		if (value !== undefined) {
			const conflict = await detectConflict(key, value, existing)
			if (conflict) {
				conflictResults.push({
					field: key,
					previous: conflict.previous,
					new: conflict.new,
				})
				await saveConflict(key, existing[key], value, conversationId)
			}
		}
	}

	// Merge with existing preferences
	const newPreferences = {
		...existing,
		...input,
		updatedAt: new Date().toISOString(),
	}

	if (existingResult[0]) {
		await db
			.update(travelProfile)
			.set({
				preferences: newPreferences as any,
				updatedAt: new Date(),
			})
			.where(eq(travelProfile.id, existingResult[0].id))
	} else {
		await db.insert(travelProfile).values({
			preferences: newPreferences as any,
		})
	}

	return {
		updated: true,
		conflicts: conflictResults,
	}
})

// Simple conflict check without saving
export async function checkConflicts(
	input: Record<string, unknown>,
): Promise<Array<{ field: string; previous: string; new: string }> | null> {
	const existingResult = await db
		.select()
		.from(travelProfile)
		.orderBy(desc(travelProfile.updatedAt))
		.limit(1)

	const existing = (existingResult[0]?.preferences as Record<string, unknown>) ?? {}
	const conflicts: Array<{ field: string; previous: string; new: string }> = []

	for (const [key, value] of Object.entries(input)) {
		if (value !== undefined) {
			const conflict = await detectConflict(key, value, existing)
			if (conflict) {
				conflicts.push({
					field: key,
					previous: conflict.previous,
					new: conflict.new,
				})
			}
		}
	}

	return conflicts.length > 0 ? conflicts : null
}

