function Tag({ children }: { children: React.ReactNode }) {
	return (
		<span className="rounded-full border border-[var(--chip-line)] bg-[var(--chip-bg)] px-2.5 py-0.5 text-xs text-[var(--sea-ink)]">
			{children}
		</span>
	)
}

function EditableField({
	label,
	value,
	onSave,
	placeholder,
}: {
	label: string
	value?: string[] | string
	onSave: (newValue: string[]) => void
	placeholder: string
}) {
	const [editing, setEditing] = useState(false)
	const [input, setInput] = useState("")

	const items = (value as string[]) ?? []

	if (editing) {
		return (
			<div className="space-y-2">
				<p className="text-xs font-semibold uppercase tracking-wider text-[var(--sea-ink-soft)]">
					{label}
				</p>
				<div className="flex gap-2">
					<input
						type="text"
						value={input}
						onChange={(e) => setInput(e.target.value)}
						placeholder={placeholder}
						className="demo-textarea flex-1 text-sm"
						onKeyDown={(e) => {
							if (e.key === "Enter") {
								const newItems = input
									.split(",")
									.map((s) => s.trim())
									.filter(Boolean)
								onSave(newItems)
								setEditing(false)
							}
							if (e.key === "Escape") {
								setEditing(false)
							}
						}}
					/>
					<button
						onClick={() => {
							const newItems = input
								.split(",")
								.map((s) => s.trim())
								.filter(Boolean)
							onSave(newItems)
							setEditing(false)
						}}
